const jobs = $('Check Pending Jobs').all();
const profileRow = $('Load Master Profile').first();
const profile = JSON.parse(JSON.stringify(profileRow.json.profile_data));
const profileId = profileRow.json.id;
const profileVersion = profileRow.json.version;

if (profile.basics) {
  profile.basics.email = '[REDACTED]';
  profile.basics.phone = '[REDACTED]';
  profile.basics.name = 'CANDIDATE_NAME';
}

const results = [];
for (const job of jobs) {
  const j = job.json;
  results.push({
    json: {
      job_id: j.job_id,
      job_title: j.title,
      job_company: j.company || 'Not specified',
      job_description: j.description,
      job_url: j.url,
      stripped_profile: profile,
      profile_id: profileId,
      profile_version: profileVersion,
      ollama_body: JSON.stringify({
        model: "qwen2.5:7b",
        stream: false,
        format: "json",
        messages: [
          { role: "system", content: "You are an expert UK recruitment analyst. Analyse the job description and extract structured requirements. Return valid JSON only." },
          { role: "user", content: "Analyse this job and return JSON with: cv_type_recommended (corporate_ld or academic or hybrid), essential_requirements (array of strings), desirable_requirements (array of strings), keywords (array of strings), cipd_required (boolean), red_flags (array of strings).\n\nJob Title: " + j.title + "\nCompany: " + (j.company || 'Not specified') + "\n\n" + j.description }
        ]
      })
    }
  });
}
return results;

const items = $input.all();
const tenantId = items[0]?.json?.tenant_id || '';
const results = [];

for (const item of items) {
  const response = item.json;
  const prev = $('Prepare JD Analysis').first().json;
  const packageId = $('Create CV Package').first().json.id;

  const analysisText = response.content ? response.content[0].text : (response.message ? response.message.content : '');
  let analysis = {};
  try {
    const jsonMatch = analysisText.match(/\{[\s\S]*\}/);
    if (jsonMatch) analysis = JSON.parse(jsonMatch[0]);
  } catch(e) {
    analysis = { cv_type_recommended: 'corporate_ld', keywords: [], essential_requirements: [], error: e.message };
  }

  const cvType = analysis.cv_type_recommended || 'corporate_ld';
  const profile = prev.stripped_profile;

  // Build a compact text profile instead of full JSON
  let profileText = 'CANDIDATE: ' + (profile.basics ? profile.basics.title_variants[cvType === 'academic' ? 'academic' : 'corporate_ld'] || '' : '') + '\n';
  profileText += 'Location: Maidenhead, Berkshire, UK\n';
  profileText += 'Right to work: Yes, no sponsorship needed\n\n';

  profileText += 'QUALIFICATIONS:\n';
  if (profile.qualifications) {
    for (const q of profile.qualifications) {
      profileText += '- ' + (q.display_variants ? q.display_variants[cvType === 'academic' ? 'academic' : 'corporate'] || q.level + ' ' + q.field : q.level + ' ' + q.field) + '\n';
    }
  }

  profileText += '\nWORK EXPERIENCE:\n';
  if (profile.work_experience) {
    for (const w of profile.work_experience) {
      const pos = w.position_variants ? w.position_variants[cvType === 'academic' ? 'academic' : 'corporate'] || w.position : w.position;
      profileText += '\n' + pos + ' | ' + w.company + ' (' + w.start_date + ' - ' + w.end_date + ')\n';
      if (w.highlights) {
        for (const h of w.highlights) {
          const txt = h.text_variants ? h.text_variants[cvType === 'academic' ? 'academic' : 'corporate'] || h.text : h.text;
          profileText += '  - ' + txt + '\n';
        }
      }
    }
  }

  profileText += '\nSKILLS: ';
  if (profile.skills) {
    profileText += profile.skills.map(s => s.name).join(', ');
  }

  profileText += '\n\nTECHNICAL SKILLS: ';
  if (profile.technical_skills) {
    profileText += Object.values(profile.technical_skills).flat().join(', ');
  }

  const cvBody = JSON.stringify({
    model: "qwen2.5:7b",
    stream: false,
    format: "json",
    messages: [
      { role: "system", content: "You are an expert UK CV writer. Return valid JSON with: professional_summary (string, 3-4 sentences), work_experience (array of {company, position, dates, highlights: array of strings}), education (array of {qualification, institution, year}), skills (array of strings), keywords_included (array), gaps_identified (array), match_percentage (number 0-100). NEVER invent experience. Use UK English." },
      { role: "user", content: "Generate a tailored CV for:\n\nJOB: " + (analysis.essential_requirements || []).join(', ') + "\nKEYWORDS: " + (analysis.keywords || []).join(', ') + "\n\n" + profileText }
    ]
  });

  results.push({
    json: {
        tenant_id: tenantId,
      job_id: prev.job_id,
      job_title: prev.job_title,
      job_company: prev.job_company,
      job_url: prev.job_url,
      stripped_profile: prev.stripped_profile,
      profile_id: prev.profile_id,
      profile_version: prev.profile_version,
      analysis: analysis,
      cv_type: cvType,
      package_id: packageId,
      jd_input_tokens: response.usage ? response.usage.input_tokens : 0,
      jd_output_tokens: response.usage ? response.usage.output_tokens : 0,
      jd_model: response.model || 'claude-haiku-4-5-20251001',
      ollama_cv_body: cvBody
    }
  });
}
return results;

